+import Yoga from 'yoga-layout';
+import {type DOMElement, type DOMNode} from './dom.js';
+
+type Track =
+	| {type: 'fixed'; size: number}
+	| {type: 'auto'}
+	| {type: 'fr'; fraction: number}
+	| {type: 'minmax'; min: number; max: number | 'fr'};
+
+type Placement = {start: number; end: number};
+
+const trackPattern = /minmax\\([^)]*\\)|\\S+/g;
+
+const parseTracks = (value: string | undefined): Track[] => {
+	if (!value) {
+		return [{type: 'auto'}];
+	}
+
+	return (value.match(trackPattern) ?? []).map(token => {
+		if (token === 'auto') {
+			return {type: 'auto'};
+		}
+
+		const minmax = /^minmax\\(\\s*(\\d+(?:\\.\\d+)?)\\s*,\\s*(\\d+(?:\\.\\d+)?|\\d+(?:\\.\\d+)?fr)\\s*\\)$/.exec(token);
+		if (minmax) {
+			const max = minmax[2]!;
+			return {type: 'minmax', min: Number(minmax[1]), max: max.endsWith('fr') ? 'fr' : Number(max)};
+		}
+
+		if (/^\\d+(?:\\.\\d+)?fr$/.test(token)) {
+			return {type: 'fr', fraction: Number.parseFloat(token)};
+		}
+
+		return {type: 'fixed', size: Number(token)};
+	});
+};
+
+const parsePlacement = (value: number | string | undefined): Placement | undefined => {
+	if (typeof value === 'number') {
+		return {start: value, end: value + 1};
+	}
+
+	if (typeof value === 'string') {
+		const match = /^(\\d+)\\s*\\/\\s*(\\d+)$/.exec(value);
+		if (match) {
+			return {start: Number(match[1]), end: Number(match[2])};
+		}
+		if (/^\\d+$/.test(value)) {
+			const start = Number(value);
+			return {start, end: start + 1};
+		}
+	}
+};
+
+const gridChildren = (node: DOMElement): DOMElement[] =>
+	node.childNodes.filter((child): child is DOMElement => child.yogaNode !== undefined);
+
+const resolveTracks = (tracks: Track[], available: number, gap: number, intrinsic: number[]): number[] => {
+	const sizes = tracks.map((track, index) => {
+		if (track.type === 'fixed') return track.size;
+		if (track.type === 'auto') return intrinsic[index] ?? 0;
+		if (track.type === 'minmax') return Math.max(track.min, Math.min(intrinsic[index] ?? track.min, typeof track.max === 'number' ? track.max : Number.POSITIVE_INFINITY));
+		return 0;
+	});
+	const fraction = tracks.reduce((total, track) => total + (track.type === 'fr' ? track.fraction : track.type === 'minmax' && track.max === 'fr' ? 1 : 0), 0);
+	const remaining = Math.max(0, available - sizes.reduce((total, size) => total + size, 0) - gap * Math.max(0, tracks.length - 1));
+	if (fraction > 0) {
+		tracks.forEach((track, index) => {
+			if (track.type === 'fr') sizes[index] = remaining * track.fraction / fraction;
+			if (track.type === 'minmax' && track.max === 'fr') sizes[index] += remaining / fraction;
+		});
+	}
+	return sizes;
+};
+
+const occupied = (used: Set<string>, row: number, column: number, rowEnd: number, columnEnd: number): boolean => {
+	for (let y = row; y < rowEnd; y++) for (let x = column; x < columnEnd; x++) if (used.has(`${y}:${x}`)) return true;
+	return false;
+};
+
+const applyGrid = (node: DOMElement): void => {
+	const columns = parseTracks(node.style.gridTemplateColumns);
+	let rows = parseTracks(node.style.gridTemplateRows);
+	const children = gridChildren(node);
+	const placements: Array<{child: DOMElement; column: Placement; row: Placement}> = [];
+	const used = new Set<string>();
+	let cursorRow = 1;
+	let cursorColumn = 1;
+
+	for (const child of children) {
+		const requestedColumn = parsePlacement(child.style.gridColumn);
+		const requestedRow = parsePlacement(child.style.gridRow);
+		const column = requestedColumn ?? {start: cursorColumn, end: cursorColumn + 1};
+		let row = requestedRow ?? {start: cursorRow, end: cursorRow + 1};
+		if (!requestedColumn || !requestedRow) {
+			while (occupied(used, row.start, column.start, row.end, column.end) || column.end - 1 > columns.length) {
+				cursorColumn++;
+				if (cursorColumn > columns.length) { cursorColumn = 1; cursorRow++; }
+				if (!requestedColumn) { column.start = cursorColumn; column.end = cursorColumn + 1; }
+				if (!requestedRow) { row = {start: cursorRow, end: cursorRow + 1}; }
+			}
+		}
+		for (let y = row.start; y < row.end; y++) for (let x = column.start; x < column.end; x++) used.add(`${y}:${x}`);
+		placements.push({child, column, row});
+		cursorColumn = column.end;
+		if (cursorColumn > columns.length) { cursorColumn = 1; cursorRow = row.start + 1; }
+	}
+
+	const rowCount = Math.max(rows.length, ...placements.map(item => item.row.end - 1), 1);
+	while (rows.length < rowCount) rows.push({type: 'auto'});
+	const columnIntrinsic = Array<number>(columns.length).fill(0);
+	const rowIntrinsic = Array<number>(rows.length).fill(0);
+	for (const {child, column, row} of placements) {
+		if (column.end === column.start + 1) columnIntrinsic[column.start - 1] = Math.max(columnIntrinsic[column.start - 1]!, child.yogaNode!.getComputedWidth());
+		if (row.end === row.start + 1) rowIntrinsic[row.start - 1] = Math.max(rowIntrinsic[row.start - 1]!, child.yogaNode!.getComputedHeight());
+	}
+	const yoga = node.yogaNode!;
+	const columnGap = node.style.columnGap ?? node.style.gap ?? 0;
+	const rowGap = node.style.rowGap ?? node.style.gap ?? 0;
+	const availableWidth = yoga.getComputedWidth() - yoga.getComputedPadding(Yoga.EDGE_LEFT) - yoga.getComputedPadding(Yoga.EDGE_RIGHT) - yoga.getComputedBorder(Yoga.EDGE_LEFT) - yoga.getComputedBorder(Yoga.EDGE_RIGHT);
+	const availableHeight = yoga.getComputedHeight() - yoga.getComputedPadding(Yoga.EDGE_TOP) - yoga.getComputedPadding(Yoga.EDGE_BOTTOM) - yoga.getComputedBorder(Yoga.EDGE_TOP) - yoga.getComputedBorder(Yoga.EDGE_BOTTOM);
+	const columnSizes = resolveTracks(columns, availableWidth, columnGap, columnIntrinsic);
+	const rowSizes = resolveTracks(rows, availableHeight, rowGap, rowIntrinsic);
+	const columnOffsets = columnSizes.map((_, index) => columnSizes.slice(0, index).reduce((total, size) => total + size, 0) + columnGap * index);
+	const rowOffsets = rowSizes.map((_, index) => rowSizes.slice(0, index).reduce((total, size) => total + size, 0) + rowGap * index);
+
+	for (const {child, column, row} of placements) {
+		const childYoga = child.yogaNode!;
+		childYoga.setPositionType(Yoga.POSITION_TYPE_ABSOLUTE);
+		childYoga.setPosition(Yoga.EDGE_LEFT, columnOffsets[column.start - 1]!);
+		childYoga.setPosition(Yoga.EDGE_TOP, rowOffsets[row.start - 1]!);
+		childYoga.setWidth(columnSizes.slice(column.start - 1, column.end - 1).reduce((total, size) => total + size, 0) + columnGap * (column.end - column.start - 1));
+		childYoga.setHeight(rowSizes.slice(row.start - 1, row.end - 1).reduce((total, size) => total + size, 0) + rowGap * (row.end - row.start - 1));
+	}
+};
+
+const restoreChildren = (node: DOMNode): void => {
+	if (node.yogaNode) {
+		// Reapply the declared styles so moving an item in or out of a grid is safe.
+		if (node.parentNode?.style.display === 'grid') {
+			node.yogaNode.setPositionType(Yoga.POSITION_TYPE_RELATIVE);
+		}
+	}
+	if ('childNodes' in node) for (const child of node.childNodes) restoreChildren(child);
+};
+
+export const calculateGridLayout = (root: DOMElement): void => {
+	restoreChildren(root);
+	const visit = (node: DOMElement): void => {
+		if (node.style.display === 'grid' && node.yogaNode) applyGrid(node);
+		for (const child of node.childNodes) if ('childNodes' in child) visit(child);
+	};
+	visit(root);
+};
